public class MutualRec {
    static boolean isEven(int n) {
        if (n == 0) return true;
        return isOdd(n - 1);
    }
    static boolean isOdd(int n) {
        if (n == 0) return false;
        return isEven(n - 1);
    }
    public static void main(String[] args) {
        System.out.println(isEven(4));
        System.out.println(isOdd(3));
        System.out.println(isEven(1));
    }
}
